import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { practiceAPI } from '../services/api';
import { useLanguage } from '../contexts/LanguageContext';
import './Practice.css';

const DIFF = {
  easy:   { color: '#0891b2', bg: '#cffafe', border: '#67e8f9', label: 'Easy',   paLabel: 'ਆਸਾਨ',  desc: 'Short sessions to build confidence', paDesc: 'ਭਰੋਸਾ ਬਣਾਉਣ ਲਈ ਛੋਟੇ ਸੈਸ਼ਨ' },
  medium: { color: '#7c3aed', bg: '#ede9fe', border: '#c4b5fd', label: 'Medium', paLabel: 'ਦਰਮਿਆਨਾ', desc: 'Balanced speed and accuracy drills', paDesc: 'ਸੰਤੁਲਿਤ ਸਪੀਡ ਅਤੇ ਸ਼ੁੱਧਤਾ ਅਭਿਆਸ' },
  hard:   { color: '#ea580c', bg: '#ffedd5', border: '#fdba74', label: 'Pro',    paLabel: 'ਮਾਹਿਰ',  desc: 'Push your limits with advanced text', paDesc: 'ਉੱਨਤ ਪਾਠ ਨਾਲ ਆਪਣੀਆਂ ਸੀਮਾਵਾਂ ਪਾਰ ਕਰੋ' },
};

const Practice = () => {
  const navigate   = useNavigate();
  const { language } = useLanguage();
  const isPa = language === 'punjabi';

  const [sessions, setSessions] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [error, setError]       = useState(null);

  useEffect(() => { loadSessions(); }, [language]);

  const loadSessions = async () => {
    setLoading(true);
    try {
      const res = await practiceAPI.getAll(language);
      setSessions(res.data || []);
    } catch {
      setError('Failed to load practice sessions');
    } finally {
      setLoading(false);
    }
  };

  const grouped = {
    easy:   sessions.filter(s => s.difficulty === 'easy'),
    medium: sessions.filter(s => s.difficulty === 'medium'),
    hard:   sessions.filter(s => s.difficulty === 'hard'),
  };

  if (loading) return <div className="pr-loading">Loading...</div>;
  if (error)   return <div className="pr-error">{error}</div>;

  return (
    <div className="pr-container">
      <div className="pr-header">
        <h1 className="pr-title" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
          {isPa ? 'ਅਭਿਆਸ ਮੋਡ' : 'Practice Mode'}
        </h1>
        <p className="pr-subtitle" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
          {isPa ? 'ਆਪਣੀ ਟਾਈਪਿੰਗ ਸਪੀਡ ਅਤੇ ਸ਼ੁੱਧਤਾ ਸੁਧਾਰੋ' : 'Sharpen your typing speed and accuracy with timed sessions'}
        </p>
      </div>

      <div className="pr-lanes">
        {['easy', 'medium', 'hard'].map(d => {
          const { color, bg, border, label, paLabel, desc, paDesc } = DIFF[d];
          const list = grouped[d];

          return (
            <div key={d} className="pr-lane" style={{ borderColor: border }}>
              {/* Lane header */}
              <div className="pr-lane-header" style={{ background: bg, borderColor: border }}>
                <div className="pr-lane-dot" style={{ background: color }} />
                <div className="pr-lane-info">
                  <span className="pr-lane-label"
                    style={{ color, fontFamily: isPa ? "'Raavi','Noto Sans Gurmukhi',sans-serif" : undefined }}>
                    {isPa ? paLabel : label}
                  </span>
                  <span className="pr-lane-desc"
                    style={{ color, fontFamily: isPa ? "'Raavi','Noto Sans Gurmukhi',sans-serif" : undefined }}>
                    {isPa ? paDesc : desc}
                  </span>
                </div>
                <span className="pr-lane-count" style={{ color }}>
                  {list.length}
                </span>
              </div>

              {/* Session cards */}
              <div className="pr-cards">
                {list.length === 0 ? (
                  <div className="pr-empty" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
                    {isPa ? 'ਕੋਈ ਸੈਸ਼ਨ ਨਹੀਂ' : 'No sessions yet'}
                  </div>
                ) : list.map(s => (
                  <div key={s._id} className="pr-card" style={{ borderColor: s.bestWpm ? color : border }}>
                    {/* Session number + title */}
                    <div className="pr-card-top">
                      <span className="pr-session-num" style={{ background: bg, color }}>{s.sessionNumber}</span>
                      <div className="pr-card-titles">
                        <span className="pr-card-title"
                          style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
                          {s.title}
                        </span>
                        <span className="pr-card-desc"
                          style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
                          {s.description || ''}
                        </span>
                      </div>
                      <span className="pr-dur" style={{ color }}>{s.duration || 5} min</span>
                    </div>

                    {/* Best score + button */}
                    <div className="pr-card-bottom">
                      {s.bestWpm
                        ? <span className="pr-best" style={{ color }}>
                            {isPa ? `ਵਧੀਆ: ${s.bestWpm} wpm` : `Best: ${s.bestWpm} wpm`}
                          </span>
                        : <span className="pr-notried" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
                            {isPa ? 'ਕੋਸ਼ਿਸ਼ ਨਹੀਂ ਕੀਤੀ' : 'Not tried yet'}
                          </span>}
                      <button
                        className="pr-btn"
                        style={s.bestWpm
                          ? { border: `1px solid ${color}`, background: '#fff', color }
                          : { background: color, border: 'none', color: '#fff' }}
                        onClick={() => navigate(`/practice/${s.sessionNumber}`)}>
                        {s.bestWpm
                          ? (isPa ? 'ਦੁਬਾਰਾ' : 'Retry')
                          : (isPa ? 'ਸ਼ੁਰੂ' : 'Start')}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Practice;
